  ('medical-tech-moex-01438', 'medical-tech', 'medical-tech-moex-114-bccd9a5a', 'sub-medical-tech-05', NULL, 'single_choice', '有  關沙門氏桿菌（Salmonella spp.）的敘述，下列何者正確？', '["都  無法在胞吞囊泡（endocytic vacuole）中複製繁殖", "可  以在無症狀帶原者的膽囊中繁殖", "傷  寒沙門氏菌（Salmonella Typhi）可以在人類以外其他動物宿主中被發現", "沙  門氏桿菌是腸道微生物相的一員，能造成宿主的伺機性感染"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:02+00:00", "source_pdf_sha1": "8bdf53b80ea0", "answer_pdf_sha1": "e0c8c1d14a30", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學與臨床微生物學（包括細菌與黴菌）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
